import { describe, expect, it } from 'vitest';
import { createObserver } from '../void-game-engine';
import {
  evaluateTopologyTicks,
  forgeGnotTopology,
  forgeTopology,
  type TopologyASTNode,
} from '../void-user-scripting';

const SIMPLE_AST: TopologyASTNode[] = [
  {
    type: 'Action',
    actionType: 'move',
  },
  {
    type: 'Action',
    actionType: 'rest',
  },
];

describe('void-user-scripting', () => {
  it('forges first-class gnot topologies with manifest + digest metadata', () => {
    const observer = createObserver(
      'did:key:void-author',
      7,
      'scientist',
      'builder',
      'fermion'
    );

    const topology = forgeGnotTopology(
      observer,
      'Void Navigator',
      [
        'gnot void-navigator v0.9',
        'using gnosis',
        'pathfinder is using gnosis, learn(., {seed:7})',
      ].join('\n'),
      SIMPLE_AST
    );

    expect(topology.sourceLanguage).toBe('gnot');
    expect(topology.sourceCode.endsWith('\n')).toBe(true);
    expect(topology.sourceGGCode).toBe(topology.sourceCode);
    expect(topology.sourceDigest).toMatch(/^fnv1a32:[0-9a-f]{8}:\d+$/u);
    expect(topology.gnotManifest?.appId).toBe('void-navigator');
    expect(topology.gnotManifest?.version).toBe('0.9');
    expect(topology.gnotManifest?.declaredNamespaces).toContain('gnosis');
  });

  it('rejects malformed gnot source at forge time', () => {
    const observer = createObserver(
      'did:key:void-author',
      11,
      'scientist',
      'builder',
      'fermion'
    );

    expect(() => {
      forgeGnotTopology(
        observer,
        'Broken Topology',
        ['using gnosis', 'pathfinder is using gnosis, learn(., {seed:11})'].join(
          '\n'
        ),
        SIMPLE_AST
      );
    }).toThrow(/invalid_gnot_source/u);
  });

  it('preserves legacy gg forging and tick execution semantics', () => {
    const observer = createObserver(
      'did:key:legacy-author',
      21,
      'scientist',
      'mystic',
      'fermion'
    );

    const topology = forgeTopology(
      observer,
      'Legacy GG',
      'entry -> step -> fold',
      SIMPLE_AST
    );

    const execution = evaluateTopologyTicks(observer, topology, 1);
    expect(execution.executedNodes).toBe(1);
    expect(execution.haltedDueToEnergy).toBe(false);
    expect(execution.nextTopologyState.currentTickIndex).toBe(1);
    expect(execution.state.energy).toBeLessThan(observer.energy);
    expect(topology.sourceLanguage).toBe('gg');
  });
});
